import { useRef, useState } from "react";
import { motion } from "framer-motion";
import { SectionLabel, sectionTitle } from "./Skills";

export default function Contact({ contact }) {
  const [copied, setCopied] = useState(false);
  const magnetRefs = useRef([]);

  const items = [
    { icon: "✉", label: "Email", value: contact.email, href: `mailto:${contact.email}`, copy: true },
    { icon: "📞", label: "Phone", value: contact.phone, href: `tel:${contact.phone}` },
    { icon: "in", label: "LinkedIn", value: contact.linkedin, href: contact.linkedinUrl, external: true },
    { icon: "📍", label: "Location", value: contact.location, href: null },
  ];

  const handleCopy = (text) => {
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleMouseMove = (e, i) => {
    const el = magnetRefs.current[i];
    if (!el) return;
    const r = el.getBoundingClientRect();

    const x = (e.clientX - r.left - r.width / 2) * 0.08;
    const y = (e.clientY - r.top - r.height / 2) * 0.08;

    el.style.transform = `translate(${x}px, ${y}px)`;

    // glow follow
    el.style.setProperty("--x", `${e.clientX - r.left}px`);
    el.style.setProperty("--y", `${e.clientY - r.top}px`);
  };

  const resetMagnet = (i) => {
    const el = magnetRefs.current[i];
    if (el) el.style.transform = "translate(0,0)";
  };

  const container = {
    hidden: {},
    show: { transition: { staggerChildren: 0.11 } },
  };

  const fadeUp = {
    hidden: { opacity: 0, y: 36 },
    show: { opacity: 1, y: 0, transition: { duration: 0.55, ease: "easeOut" } },
  };

  return (
    <>
      <style>{`
        /* ===== SECTION (MATCH EXPERIENCE EXACTLY) ===== */
        .contact-section {
          padding: clamp(2.5rem, 6vw, 5rem) clamp(1.25rem, 5vw, 4rem);
          width: 100%;
          max-width: 1400px;

          margin-left: clamp(0px, 1.5vw, 30px);
          margin-right: auto;
        }

        /* ===== HEADER ===== */
        .contact-header {
          text-align: left;
          margin-bottom: 1.25rem;
          max-width: 850px;
        }

        .contact-heading {
          text-align: left !important;
          margin-bottom: 0.75rem;
        }

        .contact-desc {
          color: var(--muted);
          font-size: clamp(0.85rem, 1.2vw, 0.95rem);
          line-height: 1.7;
          margin: 0;

          white-space: nowrap;
          overflow: hidden;
          text-overflow: ellipsis;
        }

        @media (max-width: 1024px) {
          .contact-desc {
            white-space: normal;
          }
        }

        /* ===== GRID ===== */
        .contact-grid {
          display: grid;
          grid-template-columns: repeat(auto-fit, minmax(230px, 1fr));
          gap: clamp(1rem, 2vw, 1.4rem);
          margin-top: 1.25rem;
        }

        /* ===== CARD ===== */
        .contact-card {
          background: var(--surface2);
          border: 1px solid var(--border);
          border-radius: var(--radius);
          padding: clamp(1.25rem, 3.5vw, 2.25rem);
          display: flex;
          flex-direction: column;
          gap: 8px;
          cursor: pointer;
          transition: all 0.3s ease;
          position: relative;
          overflow: hidden;
        }

        /* glow effect */
        .contact-card::before {
          content: "";
          position: absolute;
          inset: 0;
          background: radial-gradient(circle at var(--x, 50%) var(--y, 50%), rgba(0,229,255,0.15), transparent 60%);
          opacity: 0;
          transition: opacity 0.3s ease;
        }

        .contact-card:hover::before {
          opacity: 1;
        }

        .contact-card:hover {
          border-color: var(--accent);
          box-shadow: 0 10px 30px rgba(0,229,255,0.25);
          transform: translateY(-4px);
        }

        .contact-icon {
          font-size: 1.3rem;
        }

        .contact-lbl {
          font-size: 0.7rem;
          color: var(--muted);
          font-weight: 700;
          letter-spacing: 0.12em;
          text-transform: uppercase;
        }

        .contact-val {
          font-size: clamp(0.8rem, 1vw, 0.9rem);
          color: var(--text);
          text-decoration: none;
        }

        .contact-val:hover {
          color: var(--accent);
        }

        .contact-val--copied {
          color: var(--accent);
        }

        /* ===== CTA ===== */
        .contact-cta-row {
          margin-top: clamp(2rem, 4vw, 3rem);
          display: flex;
          justify-content: center;
        }

        .contact-cta {
          display: inline-flex;
          align-items: center;
          gap: 10px;
          background: linear-gradient(135deg, var(--accent), var(--accent2));
          color: #fff;
          padding: 12px 30px;
          border-radius: 999px;
          font-weight: 700;
          text-decoration: none;
          transition: all 0.3s ease;
          position: relative;
        }

        .contact-cta::after {
          content: "";
          position: absolute;
          inset: -2px;
          border-radius: inherit;
          background: linear-gradient(135deg, var(--accent), var(--accent2));
          filter: blur(10px);
          opacity: 0;
          transition: 0.3s;
          z-index: -1;
        }

        .contact-cta:hover::after {
          opacity: 1;
        }

        .contact-cta:hover {
          transform: scale(1.06);
        }

        /* ===== FOOTER ===== */
        .contact-footer {
          text-align: center;
          margin-top: clamp(2.5rem, 5vw, 4rem);
          color: var(--muted);
          font-size: 0.8rem;
        }
      `}</style>

      <section className="contact-section" id="contact">
        <motion.div variants={container} initial="hidden" whileInView="show" viewport={{ once: true }}>
          <div className="contact-header">
            <SectionLabel text="Contact" />

            <motion.h2 className="contact-heading" style={sectionTitle} variants={fadeUp}>
              Let's Build Something
            </motion.h2>

            <motion.p className="contact-desc" variants={fadeUp}>
              Available for full-time roles and exciting fintech and enterprise projects. Let's connect and build scalable, high-performance systems together.
            </motion.p>
          </div>

          <motion.div className="contact-grid" variants={container}>
            {items.map((item, i) => (
              <motion.div
                key={i}
                ref={(el) => (magnetRefs.current[i] = el)}
                className="contact-card"
                variants={fadeUp}
                onMouseMove={(e) => handleMouseMove(e, i)}
                onMouseLeave={() => resetMagnet(i)}
                onClick={() => item.copy && handleCopy(item.value)}
              >
                <span className="contact-icon">{item.icon}</span>
                <span className="contact-lbl">{item.label}</span>

                {item.href ? (
                  <a
                    href={item.href}
                    className={`contact-val${item.copy && copied ? " contact-val--copied" : ""}`}
                    target={item.external ? "_blank" : undefined}
                    rel={item.external ? "noopener noreferrer" : undefined}
                    onClick={(e) => {
                      if (item.copy) {
                        e.preventDefault();
                        handleCopy(item.value);
                      }
                    }}
                  >
                    {item.copy && copied ? "✓ Copied!" : item.value}
                  </a>
                ) : (
                  <span className="contact-val">{item.value}</span>
                )}
              </motion.div>
            ))}
          </motion.div>

          <div className="contact-cta-row">
            <motion.a href={`mailto:${contact.email}`} className="contact-cta">
              ✉ Send Email
            </motion.a>
          </div>

          <motion.p className="contact-footer">
            Built with React · Designed to impress · © {new Date().getFullYear()} Akash Chavan
          </motion.p>
        </motion.div>
      </section>
    </>
  );
}
